var e=[{id:`L2_1`,type:`dialog`,speaker:`PRESIDENT_SCHOOL_NULL_NULL`,text:{KOREA:`깊게 베이진 않았어요. 다행히 급소는 잘 피했네요.`,JPN:`深く斬られたわけではないですね。幸い、急所は外れてます。`,ENG:`The wound is not deep. Fortunately, it missed your vital points.`,TWN:`下手不重，幸好沒有傷到要害。`},stage:{bg:`CLAN_001`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`PRESIDENT_SCHOOL_NULL_NULL`,text:{KOREA:`소독을 할 테니 따끔해도 참아요.`,JPN:`消毒しますので、痛くても我慢してください。`,ENG:`Stay still. The disinfectant is going to sting.`,TWN:`我現在要替你消毒，會有點刺痛，你忍耐一下。`},stage:{bg:`CLAN_001`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`CLAN_001`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`PRESIDENT_SCHOOL_NULL_NULL`,text:{KOREA:`아까부터 빤히 쳐다보고 있는데, 뭔가 하고 싶은 말이라도 있나요?`,JPN:`さっきからずっと私を見つめていますけど、何か話したいことでもありますか？`,ENG:`You have been staring at me this whole time. Is there something you wish to say to me?`,TWN:`你從剛才就一直盯著我，是有什麼話想說嗎？`},stage:{bg:`CLAN_001`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`그대와 겨뤄보고 싶소.`,JPN:`貴殿と戦ってみたいです。`,ENG:`I want to challenge you to a duel.`,TWN:`在下想向你下戰帖。`},stage:{bg:`CLAN_001`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`PRESIDENT_SCHOOL_NULL_NULL`,text:{KOREA:`수업시간 외에 싸움을 거는 건 아카데미 교칙 위반입니다.`,JPN:`授業時間外で喧嘩を売ることはアカデミーの校則違反です。`,ENG:`Fighting outside of class is against the rules of the Academy.`,TWN:`上課時間外的對決是違反校規的。`},stage:{bg:`CLAN_001`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`PRESIDENT_SCHOOL_NULL_NULL`,text:{KOREA:`앞으로도 주의해주세요.`,JPN:`これからも気をつけてください。`,ENG:`Please be mindful of that from now on.`,TWN:`再請留意。`},stage:{bg:`CLAN_001`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`음… 명심하리다.`,JPN:`む……肝に銘じておきます。`,ENG:`Mm... I shall keep that in mind.`,TWN:`嗯…在下會記住。`},stage:{bg:`CLAN_001`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`PRESIDENT_SCHOOL_NULL_NULL`,text:{KOREA:`왜 갑자기 저와 싸우고 싶어하는 거죠?`,JPN:`急にどうして私と戦いたいと思ったのですか？`,ENG:`Why do you suddenly want to fight me?`,TWN:`為什麼突然想和我決鬥呢？`},stage:{bg:`CLAN_001`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`그건… 잘 모르겠구려.`,JPN:`それは……よくわかりません。`,ENG:`That... I am not sure.`,TWN:`在下…也不知道。`},stage:{bg:`CLAN_001`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`아마 그대에게서 달콤하고 좋은 향이 나기 때문인 것 같소.`,JPN:`おそらく、貴殿から甘くて良い香りがするからかと。`,ENG:`Perhaps it is because there is a sweet, pleasant smell coming from you.`,TWN:`可能是因為你身上有一種甜甜的香味。`},stage:{bg:`CLAN_001`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`PRESIDENT_SCHOOL_NULL_NULL`,text:{KOREA:`맥락이 없는 칭찬은 상대를 당혹스럽게 만들 뿐입니다.`,JPN:`なんの脈絡もない褒め言葉は、相手を困惑させるだけです。`,ENG:`Compliments without context only cause confusion.`,TWN:`沒來由的稱讚只會令對方感到困惑。`},stage:{bg:`CLAN_001`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`불쾌했다면 미안하오.`,JPN:`不快にさせたら申し訳ありません。`,ENG:`I apologize if I made you feel uncomfortable.`,TWN:`讓你感到不愉快的話，在下道歉。`},stage:{bg:`CLAN_001`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`PRESIDENT_SCHOOL_NULL_NULL`,text:{KOREA:`시엘 양은 방금 죽을 뻔한 것치곤 제법 침착하군요.`,JPN:`シエルさんは、さっき死にそうになったのに結構落ち着いていますね。`,ENG:`You seem quite calm for someone who almost died.`,TWN:`希爾同學剛才面對生死一瞬間的反應很沉著呢。`},stage:{bg:`CLAN_001`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`불필요한 소란은 피우고 싶지 않을 뿐이오.`,JPN:`不要な騒ぎは起こしたくないだけです。`,ENG:`I do not wish to cause unnecessary disturbances.`,TWN:`在下只是不想造成不必要的麻煩。`},stage:{bg:`CLAN_001`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`PRESIDENT_SCHOOL_NULL_NULL`,text:{KOREA:`시엘 양이 탄환을 막지 않았다면, 사선으로 끼어든 나이엘 양이 당했겠죠.`,JPN:`シエルさんが弾丸を防いでいなかったら、射線に割り込んだナイエルさんがやられていたでしょう。`,ENG:`If you had not blocked that bullet, it would have hit Naielle, who was charging at you.`,TWN:`要不是你擋下子彈，子彈就會打到奈爾。`},stage:{bg:`CLAN_001`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`그 순간을 포착한 그대도 제법 눈썰미가 있구려.`,JPN:`その瞬間を捉えた貴殿も相当な慧眼の持ち主ですね。`,ENG:`You have a keen eye, spotting that in the spur of the moment.`,TWN:`有發現這件事的你觀察力也很敏銳。`},stage:{bg:`CLAN_001`,slots:{L:null,C:null,R:null}}}];export{e as default};